# Category: insecure_crypto

from cryptography.fernet import Fernet

# Generate and store the encryption key securely in your application config
encryption_key = Fernet.generate_key()
cipher_suite = Fernet(encryption_key)

def encrypt_credit_card_number(credit_card_number):
    return cipher_suite.encrypt(credit_card_number.encode())

def decrypt_credit_card_number(encrypted_number):
    return cipher_suite.decrypt(encrypted_number).decode()

# Example usage:
if __name__ == "__main__":
    card_number = "1234-5678-9012-3456"
    encrypted_number = encrypt_credit_card_number(card_number)
    print(f"Encrypted: {encrypted_number}")
    
    decrypted_number = decrypt_credit_card_number(encrypted_number)
    print(f"Decrypted: {decrypted_number}")